import React, { useContext, useState } from "react";
//import safeEval from "safe-eval";
import { FormContext } from "../Contexts/FormContext";
import { EventCaller, ServerEventCaller } from "../BusinessLogics/EventHandler";
import { compressBase64 } from "../../utilities/utils";

const ComboBox = ({ eid, fieldname, cap, col, mn, ev, val, cod , rid}) => {
  const {
    register,
    getValues,
    setValue,
    combodata,
    setComboData,
    elements,
    eDefHldr,
    stageGridRefs,
    watch,
    trigger,
    stageElements,
    cntrData,
    formState: { errors },
  } = useContext(FormContext);

  const FormContextdata =  {
    getValues: getValues,
    stageGridRefs: stageGridRefs,
    stageElements: stageElements,
    cntrData: cntrData,
    combodata,
    setComboData
  };

  function loadCombo(elementName){

    EventCaller(
      "reloadCombo",
      fieldname,
      elementName,
      getValues,
      combodata,
      setComboData,
      elements
    );
    
  }

  
  // const options = combodata[cod] && Object.keys(combodata[cod]).length > 0 ? combodata[cod] : [];

  const options = combodata[fieldname] && Object.keys(combodata[fieldname]).length > 0 ? combodata[fieldname] : [];

  const [formData, setFormData] = useState({});

  let clientevent = {};

  if (eDefHldr.stg.cev[fieldname]) {
    //clientevent = JSON.parse(ev.change);

    clientevent = eDefHldr.stg.cev[fieldname].ev.change;
  }

  /* store previous value to avoid event fire when tabout */
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prevState) => ({ ...prevState, [name]: value }));
  };

  const customclass = eDefHldr.stg.prp[fieldname].cls;

  return (
    <div className={`${col} mb-3 ${customclass}`}>
      <label
        htmlFor={fieldname}
        className={`${mn ? "required" : ""} form-label`}
      >
        {cap}
      </label>
      <select
        className="form-select"
        aria-label="Default select example"
        disabled={eDefHldr.stg.prp[fieldname].ro}
        {...register(fieldname, {
          required: mn,
          value: val,
          onChange: (e) => {
            // if (clientevent.fn) {
            //   EventCaller(
            //     clientevent.fn,
            //     fieldname,
            //     clientevent.outel,
            //     getValues,
            //     combodata,
            //     setComboData,
            //     elements
            //   );
            // }
            if (clientevent) {
              debugger;
            eval(clientevent)
            }

            if (eDefHldr.stg.sev[fieldname]) {
              const currentValues = watch(fieldname);

              const previousValue = formData[fieldname];

              //  if (previousValue !== currentValues) {
              ServerEventCaller(
                eDefHldr,
                getValues(),
                eDefHldr.stg.sev[fieldname].ev.change,
                stageGridRefs,
                setValue,
                FormContextdata
              );
              //handleChange(e);
              //  }
            }
          },
        })}
      >
        <option key="0" value="">
          --Select--
        </option>
        {options.map((item) => (
          <option key={item.k} value={item.k}>
            {item.v}
          </option>
        ))}
      </select>

      {/* use role="alert" to announce the error message */}

      {errors[fieldname] && errors[fieldname].type == "required" && (
        <span role="alert" style={{ color: "red", fontSize: "12px" }}>
          This field is required
        </span>
      )}
      {errors[fieldname] && errors[fieldname].type == "maxLength" && (
        <span role="alert">Max length exceeded</span>
      )}
    </div>
  );
};

export default ComboBox;
